sql:
SELECT * 
FROM atmospheric_data 
WHERE timestamp BETWEEN 'start_date' AND 'end_date';

SELECT COUNT(*) 
FROM atmospheric_data 
WHERE station_id = 1;

SELECT COUNT(*)
FROM weather_stations
WHERE station_id > 10;

SELECT COUNT(data_id) 
FROM project_data 
WHERE project_id = 1;

SELECT COUNT(DISTINCT station_id) AS num_stations
FROM atmospheric_data
WHERE data_type = 'temperature' AND timestamp BETWEEN '2022-01-01 00:00:00' AND '2022-12-31 23:59:59';

SELECT DISTINCT users.user_name, users.email
FROM users
WHERE users.user_id IN (SELECT access_logs.user_id FROM access_logs);

SELECT DISTINCT u.user_name, u.email, u.role, u.institution, u.department
FROM users u
INNER JOIN access_logs a ON u.user_id = a.user_id;

external_knowledge:
- 'Frequent users' refers to individuals who have downloaded data more than once.;
- Atmospheric conditions include pressure, temperature, IWV, and ZTD.;
- Collection methods and instruments are detailed in the `method_name` and `instrument_type` columns.;

